extends Node
class_name PlayerAnimController

@onready var anim_tree: AnimationTree = get_parent().get_node("AnimationTree")

var playback: AnimationNodeStateMachinePlayback:
	get:
		if anim_tree:
			return anim_tree.get("parameters/playback")
		return null

func set_move_input(input_vec: Vector2) -> void:
	if anim_tree:
		anim_tree.set("parameters/Locomotion/blend_position", input_vec)

func trigger_attack() -> void:
	if anim_tree:
		anim_tree.set("parameters/conditions/condition_attack", true)

func current_state() -> StringName:
	var pb = playback
	if pb:
		return pb.get_current_node()
	return &""

func _process(_delta: float) -> void:
	if anim_tree and anim_tree.get("parameters/conditions/condition_attack"):
		if current_state() == &"Attack":
			anim_tree.set("parameters/conditions/condition_attack", false)

extends SceneTree

func _init():
	print("Starting scene generation...")
	var root = Node2D.new()
	root.name = "Player"

	# 1. AnimationPlayer
	var anim_player = AnimationPlayer.new()
	anim_player.name = "AnimationPlayer"
	root.add_child(anim_player)
	anim_player.owner = root

	var library = AnimationLibrary.new()
	for anim_name in ["idle", "walk_north", "walk_south", "walk_east", "walk_west", "attack"]:
		var anim = Animation.new()
		var track_idx = anim.add_track(Animation.TYPE_VALUE)
		anim.track_set_path(track_idx, ".:position")
		anim.track_insert_key(track_idx, 0.0, Vector2.ZERO)
		library.add_animation(anim_name, anim)
	anim_player.add_animation_library("", library)

	# 2. AnimationTree
	var anim_tree = AnimationTree.new()
	anim_tree.name = "AnimationTree"
	root.add_child(anim_tree)
	anim_tree.owner = root

	var state_machine = AnimationNodeStateMachine.new()

	# Locomotion BlendSpace2D
	var locomotion_blend = AnimationNodeBlendSpace2D.new()

	var idle_node = AnimationNodeAnimation.new()
	idle_node.animation = &"idle"
	locomotion_blend.add_blend_point(idle_node, Vector2(0, 0))

	var walk_north_node = AnimationNodeAnimation.new()
	walk_north_node.animation = &"walk_north"
	locomotion_blend.add_blend_point(walk_north_node, Vector2(0, -1))

	var walk_south_node = AnimationNodeAnimation.new()
	walk_south_node.animation = &"walk_south"
	locomotion_blend.add_blend_point(walk_south_node, Vector2(0, 1))

	var walk_east_node = AnimationNodeAnimation.new()
	walk_east_node.animation = &"walk_east"
	locomotion_blend.add_blend_point(walk_east_node, Vector2(1, 0))

	var walk_west_node = AnimationNodeAnimation.new()
	walk_west_node.animation = &"walk_west"
	locomotion_blend.add_blend_point(walk_west_node, Vector2(-1, 0))

	state_machine.add_node(&"Locomotion", locomotion_blend)

	# Attack Node
	var attack_node = AnimationNodeAnimation.new()
	attack_node.animation = &"attack"
	state_machine.add_node(&"Attack", attack_node)

	state_machine.set_start_node(&"Locomotion")

	# Transitions
	var transition_to_attack = AnimationNodeStateMachineTransition.new()
	transition_to_attack.advance_mode = AnimationNodeStateMachineTransition.ADVANCE_MODE_AUTO
	transition_to_attack.advance_condition = &"condition_attack"
	state_machine.add_transition(&"Locomotion", &"Attack", transition_to_attack)

	var transition_to_locomotion = AnimationNodeStateMachineTransition.new()
	transition_to_locomotion.advance_mode = AnimationNodeStateMachineTransition.ADVANCE_MODE_AUTO
	transition_to_locomotion.switch_mode = AnimationNodeStateMachineTransition.SWITCH_MODE_AT_END
	state_machine.add_transition(&"Attack", &"Locomotion", transition_to_locomotion)

	anim_tree.tree_root = state_machine
	anim_tree.anim_player = NodePath("../AnimationPlayer")

	# 3. PlayerAnimController
	var controller = Node.new()
	controller.name = "PlayerAnimController"
	var script = load("res://scripts/PlayerAnimController.gd")
	if not script:
		printerr("Failed to load script res://scripts/PlayerAnimController.gd")
		quit(1)
		return
	controller.set_script(script)
	root.add_child(controller)
	controller.owner = root

	# Save scene
	var packed_scene = PackedScene.new()
	var pack_result = packed_scene.pack(root)
	if pack_result != OK:
		printerr("Failed to pack scene: ", pack_result)
		quit(1)
		return

	var dir = DirAccess.open("res://")
	if not dir.dir_exists("scenes"):
		dir.make_dir("scenes")

	var save_result = ResourceSaver.save(packed_scene, "res://scenes/Player.tscn")
	if save_result != OK:
		printerr("Failed to save scene: ", save_result)
		quit(1)
		return

	print("Scene generated successfully!")
	quit(0)

